from pathlib import Path

app_file = Path("src/App.tsx")

app_content = """import { useState, useEffect, useRef } from 'react'
import './App.css'

// Game constants
const GRID_SIZE = 20
const CELL_SIZE = 20
const INITIAL_SNAKE = [{ x: 10, y: 10 }]
const INITIAL_DIRECTION = { x: 1, y: 0 }
const INITIAL_FOOD = { x: 15, y: 15 }
const GAME_SPEED = 150 // ms

type Position = { x: number; y: number }
type Direction = { x: number; y: number }

function App() {
  const [snake, setSnake] = useState<Position[]>(INITIAL_SNAKE)
  const [food, setFood] = useState<Position>(INITIAL_FOOD)
  const [direction, setDirection] = useState<Direction>(INITIAL_DIRECTION)
  const [gameOver, setGameOver] = useState(false)
  const [score, setScore] = useState(0)
  const [isPaused, setIsPaused] = useState(false)
  const gameLoopRef = useRef<number | null>(null)
  const directionRef = useRef<Direction>(INITIAL_DIRECTION)

  // Generate random food position
  const generateFood = (): Position => {
    let newFood: Position
    do {
      newFood = {
        x: Math.floor(Math.random() * GRID_SIZE),
        y: Math.floor(Math.random() * GRID_SIZE),
      }
    } while (snake.some(segment => segment.x === newFood.x && segment.y === newFood.y))
    return newFood
  }

  // Game loop
  useEffect(() => {
    const moveSnake = () => {
      if (gameOver || isPaused) return

      setSnake(prevSnake => {
        const newSnake = [...prevSnake]
        const head = { ...newSnake[0] }

        // Move head
        head.x += directionRef.current.x
        head.y += directionRef.current.y

        // Check wall collision
        if (head.x < 0 || head.x >= GRID_SIZE || head.y < 0 || head.y >= GRID_SIZE) {
          setGameOver(true)
          return prevSnake
        }

        // Check self collision
        if (newSnake.some(segment => segment.x === head.x && segment.y === head.y)) {
          setGameOver(true)
          return prevSnake
        }

        newSnake.unshift(head)

        // Check food collision
        if (head.x === food.x && head.y === food.y) {
          setScore(prevScore => prevScore + 1)
          setFood(generateFood())
        } else {
          newSnake.pop()
        }

        return newSnake
      })
    }

    gameLoopRef.current = window.setInterval(moveSnake, GAME_SPEED)

    return () => {
      if (gameLoopRef.current) {
        clearInterval(gameLoopRef.current)
      }
    }
  }, [gameOver, isPaused, food])

  // Keyboard controls
  useEffect(() => {
    const handleKeyDown = (event: KeyboardEvent) => {
      const currentDirection = directionRef.current

      switch (event.key) {
        case 'ArrowUp':
          if (currentDirection.y !== 1) {
            directionRef.current = { x: 0, y: -1 }
            setDirection({ x: 0, y: -1 })
          }
          break
        case 'ArrowDown':
          if (currentDirection.y !== -1) {
            directionRef.current = { x: 0, y: 1 }
            setDirection({ x: 0, y: 1 })
          }
          break
        case 'ArrowLeft':
          if (currentDirection.x !== 1) {
            directionRef.current = { x: -1, y: 0 }
            setDirection({ x: -1, y: 0 })
          }
          break
        case 'ArrowRight':
          if (currentDirection.x !== -1) {
            directionRef.current = { x: 1, y: 0 }
            setDirection({ x: 1, y: 0 })
          }
          break
        case ' ':
          setIsPaused(prev => !prev)
          break
      }
    }

    window.addEventListener('keydown', handleKeyDown)
    return () => window.removeEventListener('keydown', handleKeyDown)
  }, [])

  const resetGame = () => {
    setSnake(INITIAL_SNAKE)
    setFood(INITIAL_FOOD)
    setDirection(INITIAL_DIRECTION)
    directionRef.current = INITIAL_DIRECTION
    setGameOver(false)
    setScore(0)
    setIsPaused(false)
  }

  return (
    <div className="game-container">
      <h1>Snake Game</h1>
      <div className="score-board">
        <span>Score: {score}</span>
        <span>High Score: {localStorage.getItem('highScore') || 0}</span>
      </div>
      <div className="game-board" style={{ width: GRID_SIZE * CELL_SIZE, height: GRID_SIZE * CELL_SIZE }}>
        {snake.map((segment, index) => (
          <div
            key={index}
            className={`snake-segment ${index === 0 ? 'head' : ''}`}
            style={{
              left: segment.x * CELL_SIZE,
              top: segment.y * CELL_SIZE,
              width: CELL_SIZE,
              height: CELL_SIZE,
            }}
          />
        ))}
        <div
          className="food"
          style={{
            left: food.x * CELL_SIZE,
            top: food.y * CELL_SIZE,
            width: CELL_SIZE,
            height: CELL_SIZE,
          }}
        />
      </div>
      {gameOver && (
        <div className="game-over">
          <h2>Game Over!</h2>
          <p>Your score: {score}</p>
          <button onClick={resetGame}>Play Again</button>
        </div>
      )}
      {isPaused && !gameOver && (
        <div className="paused">
          <h2>Paused</h2>
          <p>Press SPACE to resume</p>
        </div>
      )}
      <div className="controls">
        <p>Use arrow keys to move</p>
        <p>Press SPACE to pause/resume</p>
      </div>
    </div>
  )
}

export default App
"""

