    value: {
      getItem: vi.fn(() => null),
      setItem: vi.fn(),
      removeItem: vi.fn(),
      clear: vi.fn(),
      get length() { return 0 },
      key: vi.fn(() => null),
    },
    writable: true,
  })
})

