    render(<SnakeGame />)
    expect(screen.getByText(/Snake Game/i)).toBeTruthy()
  })

  it('displays initial score of 0', () => {
    render(<SnakeGame />)
    expect(screen.getByText(/Score: 0/)).toBeTruthy()
  })

  it('shows the snake segments on the board', () => {
    render(<SnakeGame />)
    const gameBoard = screen.getByRole('region', { name: /game board/i })
    expect(gameBoard).toBeTruthy()
  })

  it('moves the snake when arrow keys are pressed', async () => {
    render(<SnakeGame />)
    const gameBoard = screen.getByRole('region', { name: /game board/i })

    // Press arrow down
    fireEvent.keyDown(gameBoard, { key: 'ArrowDown' })

    await waitFor(() => {
      // The snake should have moved
      const segments = gameBoard.querySelectorAll('.snake-segment')
      expect(segments.length).toBeGreaterThan(0)
    }, { timeout: 2000 })
  })

  it('increases score when food is eaten', async () => {
    render(<SnakeGame />)

    // Wait for initial render
    await waitFor(() => {
      expect(screen.getByText(/Score: 0/)).toBeTruthy()
    })
  })

