    render(<SnakeGame />)

    // Simulate multiple moves to hit wall
    const gameBoard = screen.getByRole('region', { name: /game board/i })

    for (let i = 0; i < 20; i++) {
      fireEvent.keyDown(gameBoard, { key: 'ArrowRight' })
    }

    await waitFor(() => {
      expect(screen.getByText(/Game Over!/i)).toBeTruthy()
    }, { timeout: 3000 })
  })

  it('allows restarting the game after game over', async () => {
    render(<SnakeGame />)

    // Simulate game over
    const gameBoard = screen.getByRole('region', { name: /game board/i })

    for (let i = 0; i < 20; i++) {
      fireEvent.keyDown(gameBoard, { key: 'ArrowRight' })
    }

    await waitFor(() => {
      expect(screen.getByText(/Game Over!/i)).toBeTruthy()
    }, { timeout: 3000 })

    // Click play again button
    const playAgainButton = screen.getByText(/Play Again/i)
    fireEvent.click(playAgainButton)

    // Game should restart
    await waitFor(() => {
      expect(screen.queryByText(/Game Over!/i)).toBeFalsy()
    }, { timeout: 2000 })
  })

  it('pauses and resumes the game with spacebar', async () => {
